-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft')
-- تحت "الاقتصاد والمالية الإسلامية" (iqtisad-maliyya-islamiyya) — تستنفد
-- العنقود بالكامل (17 تصنيفاً فرعياً بلا محتوى: المبادئ الاقتصادية، المال
-- والملكية، المحرمات المالية، صيغ التمويل الإسلامي، المصارف الإسلامية،
-- الاستثمار والزكاة عليه، التخطيط المالي الشخصي، المال والنقود، البنوك
-- التقليدية والإسلامية، الصكوك والأسهم، التأمين والتكافل، المرابحة،
-- المشاركة والمضاربة، الإجارة المنتهية بالتمليك، الأسواق المالية،
-- الحوكمة والمعايير الشرعية، النوازل المصرفية).
-- كل تصنيف يحصل على درس واحد حقيقي (lessons + lesson_sections +
-- lesson_citations)، مبني على مصادر معتمدة مسمّاة: كتب اقتصاد إسلامي
-- كلاسيكية ومعاصرة (أصول الاقتصاد الإسلامي لرفيق يونس المصري، الفقه
-- الإسلامي وأدلته للزحيلي، فقه الزكاة للقرضاوي، إصلاح المال لابن أبي
-- الدنيا، تطوير الأعمال المصرفية لسامي حمود، الأسواق المالية في ميزان
-- الفقه الإسلامي لحسين شحاتة، المعاملات المالية المعاصرة لشبير)،
-- المعايير الشرعية لهيئة أيوفي، وقرارات مجمع الفقه الإسلامي الدولي
-- المتحقَّق من أرقامها ودوراتها فعلياً عبر WebFetch/WebSearch من
-- iifa-aifi.org هذه الجلسة (لا تخمين): الفوائد المصرفية ربا قرار
-- 10(10/2) دورة جدة الثانية 1985، التأمين وإعادة التأمين قرار 9(9/2)
-- دورة جدة الثانية 1985 (متحقَّق سابقاً)، بيع المرابحة للآمر بالشراء
-- قرار 40-41(2/5و3/5) دورة الكويت الخامسة 1988، الإجارة المنتهية
-- بالتمليك قرار 110(4/12) دورة الرياض الثانية عشرة 2000.
-- كل آية استُشهد بها تحقَّقت حرفياً من public/data/quran محلياً قبل
-- الإدراج. كل حديث مستشهَد به من الصحيحين أو متفق عليه (لا حديث ذو
-- تصحيح متذبذب): حديث السلم (متفق عليه عن ابن عباس)، حديث أصناف الربا
-- الستة (رواه مسلم عن عبادة بن الصامت)، حديث «من غشنا فليس منا»
-- (رواه مسلم عن أبي هريرة).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات السبعة عشر عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) المبادئ الاقتصادية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='21cfb6f5-2ba2-4787-afa9-6cc10309b2eb' AND title='تعريف الاقتصاد الإسلامي وخصائصه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف الاقتصاد الإسلامي وخصائصه', 'الأسس والخصائص التي يقوم عليها النشاط الاقتصادي في الإسلام', '21cfb6f5-2ba2-4787-afa9-6cc10309b2eb', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وخصائصه', 'الاقتصاد الإسلامي هو النشاط المتعلق بالإنتاج والتوزيع والاستهلاك في ضوء أحكام الشريعة ومقاصدها، ومن أبرز خصائصه: ربانية المصدر لأن أحكامه مستمدة من الوحي، والتوازن بين مصلحة الفرد وحق الجماعة، والجمع بين الكسب المادي والقيمة الأخلاقية، فلا ينفصل الحلال والحرام عن باب الاقتصاد كما في سائر أبواب الفقه.', 1),
    (v_lesson, 'evidence', 'أصل الاستخلاف في المال', 'قال تعالى: ﴿آمِنُوا بِاللَّهِ وَرَسُولِهِ وَأَنْفِقُوا مِمَّا جَعَلَكُمْ مُسْتَخْلَفِينَ فِيهِ فَالَّذِينَ آمَنُوا مِنْكُمْ وَأَنْفَقُوا لَهُمْ أَجْرٌ كَبِيرٌ﴾ (الحديد: 7)، فالآية تؤسس لمبدأ أن المال أصله ملك لله والإنسان مستخلَف فيه، وهذا الأصل ينبني عليه كثير من أحكام الاقتصاد الإسلامي المتعلقة بالكسب والإنفاق.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أصول الاقتصاد الإسلامي — د. رفيق يونس المصري', 1);
  END IF;

  -- 2) المال والملكية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='18bbf92f-9315-4055-9cdd-55eb30b6987f' AND title='الملكية في الإسلام وأنواعها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الملكية في الإسلام وأنواعها', 'حقيقة الملكية الحقة لله تعالى وتقسيم الملكية إلى عامة وخاصة ومشتركة', '18bbf92f-9315-4055-9cdd-55eb30b6987f', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وأنواعها', 'الملكية الحقيقية المطلقة لله وحده، وما يملكه الإنسان إنما هو ملك نسبي مقيَّد بحدود الشرع. يقسم الفقهاء الملكية إلى ملكية خاصة (ما يختص به الفرد من مال باكتساب مشروع)، وملكية عامة (ما هو حق لعموم الأمة كالموارد الطبيعية الكبرى)، وملكية الدولة (ما تحوزه لتحقيق المصالح العامة).', 1),
    (v_lesson, 'evidence', 'دليل الملك المطلق لله', 'قال تعالى: ﴿لِلَّهِ مَا فِي السَّمَاوَاتِ وَمَا فِي الْأَرْضِ وَإِنْ تُبْدُوا مَا فِي أَنْفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُمْ بِهِ اللَّهُ﴾ (البقرة: 284)، فأثبتت الآية أن الملك المطلق لله وحده، وما للعبد من مال هو حق انتفاع واستخلاف تصرُّفه فيه محكوم بحدود الشرع.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفقه الإسلامي وأدلته — د. وهبة الزحيلي (باب الملكية وأسبابها)', 1);
  END IF;

  -- 3) المحرمات المالية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='b43746c6-ad8f-412c-b341-7057c638f36d' AND title='المحرمات المالية الكبرى: الربا والغرر وأكل المال بالباطل') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('المحرمات المالية الكبرى: الربا والغرر وأكل المال بالباطل', 'أبرز المحرمات التي تفسد المعاملات المالية في الشريعة الإسلامية', 'b43746c6-ad8f-412c-b341-7057c638f36d', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أبرز المحرمات المالية', 'حرَّمت الشريعة عدداً من صور اكتساب المال لما فيها من ظلم أو غرر: الربا وهو الزيادة المشروطة في القرض أو التفاضل والنساء في الأصناف الربوية، والغرر الفاحش وهو الجهالة الكبيرة بالمعقود عليه أو مآله، والميسر (القمار)، وأكل أموال الناس بالباطل بأي وجه من وجوه الظلم كالغش والتدليس والسرقة.', 1),
    (v_lesson, 'evidence', 'دليلها من القرآن', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَأْكُلُوا أَمْوَالَكُمْ بَيْنَكُمْ بِالْبَاطِلِ إِلَّا أَنْ تَكُونَ تِجَارَةً عَنْ تَرَاضٍ مِنْكُمْ﴾ (النساء: 29)، فأصَّلت الآية جواز الكسب عن طريق التجارة القائمة على التراضي، وحرَّمت كل صورة أخرى لأكل المال بالباطل.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الغرر وأثره في العقود في الفقه الإسلامي — د. الصديق محمد الأمين الضرير', 1);
  END IF;

  -- 4) صيغ التمويل الإسلامي
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='806c8eb0-a340-470d-a396-6936bd910357' AND title='مدخل إلى صيغ التمويل الإسلامي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مدخل إلى صيغ التمويل الإسلامي', 'الصيغ الشرعية البديلة عن القرض الربوي في تمويل الاحتياجات المالية', '806c8eb0-a340-470d-a396-6936bd910357', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أبرز الصيغ', 'طوَّر الفقه الإسلامي المعاصر عدداً من صيغ التمويل القائمة على عقود البيع والمشاركة والإجارة بدلاً من القرض بفائدة: المرابحة، والمشاركة، والمضاربة، والإجارة المنتهية بالتمليك، والسلم، والاستصناع، وكلها عقود لها أصل في الفقه الإسلامي الكلاسيكي كيَّفها الفقه المعاصر لتلبية احتياجات التمويل الحديثة.', 1),
    (v_lesson, 'evidence', 'أصالة عقد السلم شرعاً', 'عن ابن عباس رضي الله عنهما أن النبي صلى الله عليه وسلم قال: «مَنْ أَسْلَفَ فِي تَمْرٍ فَلْيُسْلِفْ فِي كَيْلٍ مَعْلُومٍ وَوَزْنٍ مَعْلُومٍ إِلَى أَجَلٍ مَعْلُومٍ» متفق عليه، وهذا الحديث أصل مشروعية عقد السلم الذي تُبنى عليه صيغ تمويل معاصرة كثيرة في الزراعة والصناعة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المعايير الشرعية — هيئة المحاسبة والمراجعة للمؤسسات المالية الإسلامية (أيوفي)', 1);
  END IF;

  -- 5) المصارف الإسلامية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='83bf55f6-492e-4ada-b77a-a8f1e4abe0d8' AND title='نشأة المصارف الإسلامية وفكرتها التأسيسية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('نشأة المصارف الإسلامية وفكرتها التأسيسية', 'الفرق الجوهري بين المصرف الإسلامي والمصرف التقليدي في مصدر التمويل', '83bf55f6-492e-4ada-b77a-a8f1e4abe0d8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'الفكرة التأسيسية', 'المصرف الإسلامي مؤسسة مالية تلتزم في جميع معاملاتها بأحكام الشريعة، فتستبدل الفائدة الربوية المشروطة على الودائع والقروض بصيغ استثمار وتمويل قائمة على المشاركة في الربح والخسارة أو البيع والإجارة، وقد بدأت التجربة المصرفية الإسلامية الحديثة عملياً في السبعينيات الميلادية بعد جهود فقهية وأكاديمية سابقة لتأصيل الفكرة.', 1),
    (v_lesson, 'evidence', 'الأصل الشرعي للفارق', 'قال تعالى: ﴿الَّذِينَ يَأْكُلُونَ الرِّبَا لَا يَقُومُونَ إِلَّا كَمَا يَقُومُ الَّذِي يَتَخَبَّطُهُ الشَّيْطَانُ مِنَ الْمَسِّ ذَلِكَ بِأَنَّهُمْ قَالُوا إِنَّمَا الْبَيْعُ مِثْلُ الرِّبَا وَأَحَلَّ اللَّهُ الْبَيْعَ وَحَرَّمَ الرِّبَا﴾ (البقرة: 275)، وهذا التفريق القرآني بين حل البيع وحرمة الربا هو الأساس الشرعي الذي قامت عليه فكرة المصرفية الإسلامية.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تطوير الأعمال المصرفية بما يتفق والشريعة الإسلامية — د. سامي حسن أحمد حمود', 1);
  END IF;

  -- 6) الاستثمار والزكاة عليه
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='a3b31ea6-92da-4fab-a5ea-9c47142fdbea' AND title='أحكام زكاة الأموال المستثمرة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أحكام زكاة الأموال المستثمرة', 'الفرق بين زكاة عروض التجارة وزكاة الأصول والأسهم الاستثمارية', 'a3b31ea6-92da-4fab-a5ea-9c47142fdbea', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'ضابطها العام', 'المال المُعَدُّ للتجارة (كعروض التجارة المتداولة) تجب زكاته على أصله وربحه معاً بحول واحد بنسبة ربع العشر (2.5%). أما الأصول الاستثمارية الثابتة التي اقتُنيت للاستغلال لا للبيع (كالعقارات المؤجَّرة والمصانع)، فالزكاة عند جمهور المعاصرين على غلتها وريعها لا على قيمة الأصل نفسه، قياساً على زكاة الزروع لا زكاة عروض التجارة.', 1),
    (v_lesson, 'evidence', 'دليلها من القرآن', 'قال تعالى: ﴿وَفِي أَمْوَالِهِمْ حَقٌّ لِلسَّائِلِ وَالْمَحْرُومِ﴾ (الذاريات: 19)، فأثبتت الآية أن في المال حقاً واجباً لغير مالكه، وهو أصل مشروعية الزكاة في كل ما يدخل تحت مسمى المال المُنَمَّى المستثمَر.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه الزكاة — د. يوسف القرضاوي', 1);
  END IF;

  -- 7) التخطيط المالي الشخصي
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='91fd0e7c-2440-46ec-b967-8b11ca9d10b0' AND title='فقه الاعتدال في تدبير المال الشخصي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فقه الاعتدال في تدبير المال الشخصي', 'الوسطية الشرعية بين الإسراف والتقتير في تدبير النفقة', '91fd0e7c-2440-46ec-b967-8b11ca9d10b0', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'مبدأ الوسطية', 'رغَّبت الشريعة في حسن تدبير المال بلا إسراف مجاوز للحاجة ولا تقتير مانع للحق الواجب، فحسن التدبير جزء من فقه المعيشة عند العلماء، ومن أهم أصوله: تقديم الأهم على المهم في النفقة، والادخار للطوارئ، والبعد عن الديون غير الضرورية.', 1),
    (v_lesson, 'evidence', 'دليلها من القرآن', 'قال تعالى في وصف عباد الرحمن: ﴿وَالَّذِينَ إِذَا أَنْفَقُوا لَمْ يُسْرِفُوا وَلَمْ يَقْتُرُوا وَكَانَ بَيْنَ ذَلِكَ قَوَامًا﴾ (الفرقان: 67)، فجعلت الآية الاعتدال بين طرفي الإسراف والتقتير من صفات المؤمنين الصادقين في تدبير أموالهم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'إصلاح المال — الحافظ ابن أبي الدنيا', 1);
  END IF;

  -- 8) المال والنقود
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='f7320e2a-b584-4a9d-bf67-d26cb73d9722' AND title='حقيقة النقود وأحكامها في الفقه الإسلامي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حقيقة النقود وأحكامها في الفقه الإسلامي', 'تطور صور النقد وحكم إلحاق الأوراق النقدية بالذهب والفضة في الأحكام', 'f7320e2a-b584-4a9d-bf67-d26cb73d9722', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تطور النقد وحكم الورقي منه', 'كان النقد في صدر الإسلام ذهباً وفضة مسكوكين، ثم استُحدثت النقود الورقية فألحقها جمهور الفقهاء المعاصرين بالذهب والفضة في أحكام الزكاة والربا اعتباراً بوظيفتها لا بجوهرها، لكونها أصبحت ثمناً للأشياء ووسيلة للتبادل والادخار كما كانت الأثمان القديمة.', 1),
    (v_lesson, 'evidence', 'دليل ضبط أصناف الربا', 'عن عبادة بن الصامت رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «الذَّهَبُ بِالذَّهَبِ، وَالْفِضَّةُ بِالْفِضَّةِ، وَالْبُرُّ بِالْبُرِّ، وَالشَّعِيرُ بِالشَّعِيرِ، وَالتَّمْرُ بِالتَّمْرِ، وَالْمِلْحُ بِالْمِلْحِ، مِثْلًا بِمِثْلٍ، سَوَاءً بِسَوَاءٍ، يَدًا بِيَدٍ، فَإِذَا اخْتَلَفَتْ هَذِهِ الْأَصْنَافُ فَبِيعُوا كَيْفَ شِئْتُمْ إِذَا كَانَ يَدًا بِيَدٍ» رواه مسلم، وهذا الحديث هو أصل بحث الفقهاء المعاصرين في إلحاق النقود الورقية بالذهب والفضة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أحكام الأوراق النقدية وقيمتها في الفقه الإسلامي — الشيخ عبد الله بن سليمان بن منيع', 1);
  END IF;

  -- 9) البنوك التقليدية والإسلامية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='e70b4727-255a-4e92-94db-974fcce80ef1' AND title='الفرق الجوهري بين البنك التقليدي والبنك الإسلامي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الفرق الجوهري بين البنك التقليدي والبنك الإسلامي', 'حكم الفوائد المصرفية وأثره في التمييز بين النظامين', 'e70b4727-255a-4e92-94db-974fcce80ef1', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'موطن الفرق', 'يقوم البنك التقليدي على أخذ الودائع وإقراضها بفائدة ثابتة مضمونة بصرف النظر عن نتيجة الاستثمار، بينما يقوم البنك الإسلامي على قبول الأموال بصيغ مشاركة أو استثمار تُقسَم فيها الأرباح بنسب متفق عليها وتُتحمَّل الخسارة بحسب طبيعة العقد لا بفائدة مضمونة مقطوعة، وهذا هو موطن الفرق الجوهري الذي قررته المجامع الفقهية.', 1),
    (v_lesson, 'evidence', 'قرار المجمع الفقهي في الفوائد المصرفية', 'قرر مجمع الفقه الإسلامي الدولي في قراره رقم 10(10/2) في دورته الثانية بجدة عام 1406هـ/1985م أن الفائدة التي تتقاضاها البنوك التقليدية على أنواع قروضها ربا محرم، لعموم دليل تحريم الربا في القرآن: ﴿يَمْحَقُ اللَّهُ الرِّبَا وَيُرْبِي الصَّدَقَاتِ﴾ (البقرة: 276).', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'قرار مجمع الفقه الإسلامي الدولي رقم 10(10/2) بشأن التعامل المصرفي بالفوائد — الدورة الثانية، جدة، 1406هـ/1985م', 1);
  END IF;

  -- 10) الصكوك والأسهم
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='e90af6d2-ca1a-4404-8a91-019113c6d9c8' AND title='التعريف بالصكوك الإسلامية والأسهم') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التعريف بالصكوك الإسلامية والأسهم', 'الفرق بين الصك الإسلامي والسند الربوي، وضوابط تداول الأسهم', 'e90af6d2-ca1a-4404-8a91-019113c6d9c8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفهما والفارق بينهما', 'الصك الإسلامي وثيقة تمثل حصة شائعة في ملكية أصل أو منفعة أو مشروع معيَّن يُشارك حامله في ربحه وخسارته، خلافاً للسند الربوي القائم على دَين بفائدة ثابتة مضمونة. أما السهم فهو حصة شائعة في رأس مال شركة، ويجوز التعامل به شرعاً إذا كان نشاط الشركة مباحاً وخلا العقد من الغرر الفاحش.', 1),
    (v_lesson, 'evidence', 'أصل المشاركة في الفقه', 'قال تعالى على لسان داود عليه السلام مقرِّراً أصل الشراكة العادلة: ﴿وَإِنَّ كَثِيرًا مِنَ الْخُلَطَاءِ لَيَبْغِي بَعْضُهُمْ عَلَى بَعْضٍ إِلَّا الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ وَقَلِيلٌ مَا هُمْ﴾ (ص: 24)، فأصَّلت الآية مشروعية الاشتراك في المال، وأن الظلم فيه غالب إلا فيمن التزم العدل، وهو أصل ينبني عليه ضبط عقود الصكوك والأسهم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المعيار الشرعي رقم (17): الصكوك الاستثمارية — هيئة المحاسبة والمراجعة للمؤسسات المالية الإسلامية (أيوفي)', 1);
  END IF;

  -- 11) التأمين والتكافل
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='6b34e5df-19b7-4b26-999a-37d7f49af404' AND title='حكم التأمين التجاري والتأمين التعاوني (التكافل)') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم التأمين التجاري والتأمين التعاوني (التكافل)', 'الفرق الشرعي بين التأمين التجاري المحرَّم والتأمين التعاوني المباح', '6b34e5df-19b7-4b26-999a-37d7f49af404', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'الفارق بين النوعين', 'التأمين التجاري عقد معاوضة يشتري فيه المؤمَّن له تعهداً بتعويض محتمل مقابل قسط محدد، وفيه غرر وربا وميسر عند جمهور الفقهاء المعاصرين. أما التأمين التعاوني (التكافل) فيقوم على تبرع المشتركين فيما بينهم لتغطية أضرار من يصيبه الضرر منهم، فيخرج بذلك عن معاوضة الغرر إلى باب التبرع والتعاون المباح.', 1),
    (v_lesson, 'evidence', 'دليل التعاون في القرآن', 'قال تعالى: ﴿وَتَعَاوَنُوا عَلَى الْبِرِّ وَالتَّقْوَى وَلَا تَعَاوَنُوا عَلَى الْإِثْمِ وَالْعُدْوَانِ﴾ (المائدة: 2)، وهذا الأصل القرآني في التعاون هو الأساس الشرعي الذي يقوم عليه التكييف الفقهي المعاصر للتأمين التعاوني.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'قرار مجمع الفقه الإسلامي الدولي رقم 9(9/2) بشأن التأمين وإعادة التأمين — الدورة الثانية، جدة، 1406هـ/1985م', 1);
  END IF;

  -- 12) المرابحة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='67b08a3e-e1b4-41fb-8ff4-fcebbaa7c37b' AND title='بيع المرابحة للآمر بالشراء وضوابطه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('بيع المرابحة للآمر بالشراء وضوابطه', 'صيغة المرابحة المصرفية المعاصرة وشروط جوازها الشرعي', '67b08a3e-e1b4-41fb-8ff4-fcebbaa7c37b', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وأبرز ضوابطها', 'المرابحة للآمر بالشراء عقد يطلب فيه شخص من مؤسسة تمويلية شراء سلعة معيَّنة ثم بيعها له بثمنها الأصلي مضافاً إليه ربح متفق عليه، بشرط أن تدخل السلعة فعلاً في ملك المؤسسة وتتحمَّل تبعتها قبل بيعها للآمر بالشراء، وإلا كانت العملية حيلة على الربا لا بيعاً حقيقياً.', 1),
    (v_lesson, 'evidence', 'أصل حل البيع', 'قال تعالى: ﴿وَأَحَلَّ اللَّهُ الْبَيْعَ وَحَرَّمَ الرِّبَا﴾ (البقرة: 275)، وعلى هذا الأصل بُنيت مشروعية بيع المرابحة بوصفه بيعاً حقيقياً بربح معلوم متى توافرت فيه شروط البيع الشرعي وانتفت عنه موانعه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'قرار مجمع الفقه الإسلامي الدولي رقم 40-41(2/5 و3/5) بشأن الوفاء بالوعد والمرابحة للآمر بالشراء — الدورة الخامسة، الكويت، 1409هـ/1988م', 1);
  END IF;

  -- 13) المشاركة والمضاربة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='3969cad6-7a2f-4b40-ad9f-1458934e6317' AND title='عقدا المشاركة والمضاربة وضوابطهما') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('عقدا المشاركة والمضاربة وضوابطهما', 'التمييز بين شركة المشاركة وعقد المضاربة في توزيع الربح والخسارة', '3969cad6-7a2f-4b40-ad9f-1458934e6317', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفهما', 'المشاركة اشتراك طرفين فأكثر برأس مال وعمل، يقتسمون الربح بنسبة متفق عليها وتوزَّع الخسارة بنسبة رأس المال إن وقعت. أما المضاربة فعقد بين صاحب مال يقدِّم رأس المال وعامل يقدِّم الجهد والخبرة، فإن ربحا اقتسما الربح بنسبة متفق عليها، وإن خسرا كانت الخسارة المالية على رب المال وحده ما لم يتعدَّ العامل أو يقصِّر، وخسر العامل جهده.', 1),
    (v_lesson, 'evidence', 'أصل المشاركة العادلة', 'قال تعالى: ﴿وَإِنَّ كَثِيرًا مِنَ الْخُلَطَاءِ لَيَبْغِي بَعْضُهُمْ عَلَى بَعْضٍ إِلَّا الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ﴾ (ص: 24)، فهذا الأصل القرآني ينبني عليه اشتراط العدل والأمانة بين الشريكين حتى تصح المشاركة والمضاربة شرعاً.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفقه الإسلامي وأدلته — د. وهبة الزحيلي (باب الشركات وعقد المضاربة)', 1);
  END IF;

  -- 14) الإجارة المنتهية بالتمليك
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='5d07f3fe-e5dc-41cb-9101-7f93f2625427' AND title='الإجارة المنتهية بالتمليك وضوابط جوازها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الإجارة المنتهية بالتمليك وضوابط جوازها', 'صيغة الإجارة التي ينتقل بها ملك العين المؤجَّرة للمستأجر بعد استيفاء شروط', '5d07f3fe-e5dc-41cb-9101-7f93f2625427', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وأبرز ضوابطها', 'الإجارة المنتهية بالتمليك عقد إجارة حقيقية يملك فيه المستأجر العين المؤجَّرة في نهاية مدة الإجارة، بشرط أن يكون عقد التمليك مستقلاً عن عقد الإجارة زماناً (كوعد بالتمليك أو عقد بيع لاحق)، وأن تكون الإجارة فعلية لا صورية ساترة لبيع بالتقسيط، وأن يبقى ضمان العين المؤجَّرة على المالك (المؤجِّر) طوال مدة الإجارة.', 1),
    (v_lesson, 'evidence', 'أصل مشروعية الإجارة', 'قال تعالى: ﴿قَالَتْ إِحْدَاهُمَا يَا أَبَتِ اسْتَأْجِرْهُ إِنَّ خَيْرَ مَنِ اسْتَأْجَرْتَ الْقَوِيُّ الْأَمِينُ﴾ (القصص: 26)، وهذه الآية أصل مشروعية عقد الإجارة الذي بُنيت عليه صورة الإجارة المنتهية بالتمليك المعاصرة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'قرار مجمع الفقه الإسلامي الدولي رقم 110(4/12) بشأن الإجارة المنتهية بالتمليك — الدورة الثانية عشرة، الرياض، 1421هـ/2000م', 1);
  END IF;

  -- 15) الأسواق المالية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='85e3963f-33a3-406d-9562-3aee37651c16' AND title='الضوابط الشرعية للتعامل في الأسواق المالية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الضوابط الشرعية للتعامل في الأسواق المالية', 'أصل جواز تداول الأسهم وضوابط منع صور المضاربة المحرَّمة', '85e3963f-33a3-406d-9562-3aee37651c16', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أبرز الضوابط', 'يجيز أكثر الفقهاء المعاصرين تداول أسهم الشركات ذات النشاط المباح بضوابط: خلو نشاط الشركة الأساسي من محرَّم كالربا والقمار، وعدم مجاوزة نسب الديون والمعاملات المشبوهة حدوداً معتبرة عند أهل الاختصاص، مع تحريم صور المضاربة الوهمية القائمة على البيع على المكشوف والغرر الفاحش لأنها من الميسر لا من التجارة الحقيقية.', 1),
    (v_lesson, 'evidence', 'الأصل القرآني للتراضي في التعامل', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَأْكُلُوا أَمْوَالَكُمْ بَيْنَكُمْ بِالْبَاطِلِ إِلَّا أَنْ تَكُونَ تِجَارَةً عَنْ تَرَاضٍ مِنْكُمْ﴾ (النساء: 29)، فربطت الآية حل الكسب بالتجارة القائمة على التراضي الحقيقي، وهو ما يميِّز التداول المشروع في الأسواق المالية عن صور المقامرة المحرَّمة فيها.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الأسواق المالية في ميزان الفقه الإسلامي — د. حسين حسين شحاتة', 1);
  END IF;

  -- 16) الحوكمة والمعايير الشرعية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='7e7d756a-bcc7-41a7-94c2-b4e16dbf33e7' AND title='الرقابة الشرعية والحوكمة في المؤسسات المالية الإسلامية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الرقابة الشرعية والحوكمة في المؤسسات المالية الإسلامية', 'دور هيئة الرقابة الشرعية في ضبط التزام المصارف الإسلامية بأحكام الشريعة', '7e7d756a-bcc7-41a7-94c2-b4e16dbf33e7', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها ودورها', 'هيئة الرقابة الشرعية جهاز مستقل من علماء الشريعة والاقتصاد داخل المؤسسة المالية الإسلامية، مهمته مراجعة العقود والمنتجات قبل تطبيقها والتأكد من مطابقتها لأحكام الشريعة، وإصدار الفتاوى اللازمة، والتدقيق الشرعي اللاحق على العمليات الفعلية، وقد وضعت هيئة أيوفي معايير موحدة لضبط عمل هذه الهيئات وحوكمتها.', 1),
    (v_lesson, 'evidence', 'أصل النصح والأمانة في المعاملة', 'عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «مَنْ غَشَّنَا فَلَيْسَ مِنَّا» رواه مسلم، وهذا الحديث أصل عام يوجب الصدق والبيان في كل معاملة مالية، وهو ما تقوم الرقابة الشرعية على ضمانه في عمل المؤسسات المالية الإسلامية.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الرقابة الشرعية في المصارف الإسلامية — د. محمد عثمان شبير', 1);
  END IF;

  -- 17) النوازل المصرفية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='f6e735f2-d852-474e-ab35-e30367256f38' AND title='منهج التعامل مع النوازل المالية والمصرفية المستجدة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('منهج التعامل مع النوازل المالية والمصرفية المستجدة', 'الأصول التي يستند إليها الفقه المعاصر في تكييف المعاملات المصرفية الجديدة', 'f6e735f2-d852-474e-ab35-e30367256f38', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريف النازلة ومنهج بحثها', 'النازلة كل مسألة مستجدة لم يرد فيها نص خاص، وقد ابتكر الفقه المصرفي المعاصر معاملات لم تكن معروفة كالتورق المنظَّم والبطاقات الائتمانية والعملات الرقمية، فيتناولها المجامع الفقهية بردها إلى أصولها الشرعية عبر القياس، والمصلحة المرسلة، وسد الذرائع، مع مراعاة فقه الموازنة بين المصالح والمفاسد في كل نازلة على حدة.', 1),
    (v_lesson, 'evidence', 'أصل التفقه المتخصص في النوازل', 'قال تعالى: ﴿وَمَا كَانَ الْمُؤْمِنُونَ لِيَنْفِرُوا كَافَّةً فَلَوْلَا نَفَرَ مِنْ كُلِّ فِرْقَةٍ مِنْهُمْ طَائِفَةٌ لِيَتَفَقَّهُوا فِي الدِّينِ وَلِيُنْذِرُوا قَوْمَهُمْ إِذَا رَجَعُوا إِلَيْهِمْ لَعَلَّهُمْ يَحْذَرُونَ﴾ (التوبة: 122)، وهذا الأصل القرآني في التخصص والتفقه هو ما تقوم عليه هيئات النوازل والمجامع الفقهية المتخصصة في القضايا المالية المصرفية المستجدة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المعاملات المالية المعاصرة — د. محمد عثمان شبير', 1);
  END IF;

  -- تحديث حالة التصنيفات السبعة عشر إلى منشور بعد اكتمال محتواها
  UPDATE categories SET status='published'
  WHERE id IN (
